args.sparql:
SELECT DISTINCT ?president ?presidentLabel ?party ?partyLabel WHERE {
  ?president wdt:P39 wd:Q312271.
  ?president p:P39 ?officeStmt.
  ?officeStmt ps:P39 wd:Q312271.
  ?officeStmt pq:P580 ?start.
  ?officeStmt pq:P582 ?end.
  FILTER(?start >= "1991-01-01T00:00:00Z"^^xsd:dateTime)
  OPTIONAL { ?president wdt:P102 ?party. }
  OPTIONAL { ?president rdfs:label ?presidentLabel filter(langMatches(lang(?presidentLabel), 'en')). }
  OPTIONAL { ?party rdfs:label ?partyLabel filter(langMatches(lang(?partyLabel), 'en')). }
}

SELECT DISTINCT ?president ?presidentLabel ?party ?partyLabel WHERE {
  ?president wdt:P39 wd:Q312271.
  ?president p:P39 ?officeStmt.
  ?officeStmt ps:P39 wd:Q312271.
  ?officeStmt pq:P580 ?start.
  ?officeStmt pq:P582 ?end.
  FILTER (STR(?start) >= "1991-01-01")
  OPTIONAL { ?president wdt:P102 ?party. }
  OPTIONAL { ?president rdfs:label ?presidentLabel FILTER (lang(?presidentLabel) = 'en'). }
  OPTIONAL { ?party rdfs:label ?partyLabel FILTER (lang(?partyLabel) = 'en'). }
}

SELECT DISTINCT ?president ?presidentLabel ?party ?partyLabel WHERE {
  ?president wdt:P39 wd:Q312271.
  ?president p:P39 ?officeStmt.
  ?officeStmt ps:P39 wd:Q312271.
  ?officeStmt pq:P580 ?start.
  ?officeStmt pq:P582 ?end.
  FILTER (STR(?start) >= "1991-01-01")
  OPTIONAL { ?president wdt:P102 ?party. }
  OPTIONAL {
    ?president rdfs:label ?presidentLabel
    FILTER (lang(?presidentLabel) = 'en')
  }
  OPTIONAL {
    ?party rdfs:label ?partyLabel
    FILTER (lang(?partyLabel) = 'en')
    FILTER (?partyLabel != "Communist Party of the Soviet Union")
  }
} ORDER BY ?start

SELECT DISTINCT ?president ?presidentLabel ?party ?partyLabel WHERE {
  ?president wdt:P39 wd:Q312271.
  ?president p:P39 ?officeStmt.
  ?officeStmt ps:P39 wd:Q312271.
  ?officeStmt pq:P580 ?start.
  ?officeStmt pq:P582 ?end.
  FILTER (STR(?start) >= "1991-01-01")
  OPTIONAL { ?president wdt:P102 ?party. }
  OPTIONAL { ?president rdfs:label ?presidentLabel FILTER (lang(?presidentLabel) = 'en') }
  OPTIONAL { ?party rdfs:label ?partyLabel FILTER (lang(?partyLabel) = 'en') FILTER (?partyLabel != "Communist Party of the Soviet Union") }
} ORDER BY ?start
